#include <bits/stdc++.h>
using namespace std;
const int maxn=3e3+5,INF=1e9;
int n,m,val[maxn],sum,ans,siz[maxn],dp[maxn][maxn],tot;
vector<pair<int,int>> g[maxn];
void dfs(int u) {
	for(int i=1; i<=n; i++) {
		dp[u][i]=-INF;
	}
	dp[u][0]=0;
	if(u>n-m) {
		siz[u]=1;
		dp[u][1]=val[u];
		return;
	}
	for(auto &ed:g[u]) {
		int v=ed.first,w=ed.second;
		dfs(v);
		for(int j=siz[u]+siz[v]; j>=1; j--) {
			for(int k=1; k<=siz[v]; k++) {
				if(j>=k)
					dp[u][j]=max(dp[u][j],dp[u][j-k]+dp[v][k]-w);
			}
		}
		siz[u]+=siz[v];
	}
}
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>m;
	for(int i=1; i<=n-m; i++) {
		int k;
		cin>>k;
		while(k--) {
			int v,w;
			cin>>v>>w;
			g[i].emplace_back(v,w);
		}
	}
	for(int i=n-m+1; i<=n; i++) {
		cin>>val[i];
	}
	dfs(1);
	for(int i=m; i>=0; i--) {
		if(dp[1][i]>=0){
			cout<<i;
			break;
		}
	}
	return 0;
}
